from typing import List, Dict, Any
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND",
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    # No filters or no results – nothing to do
    if not search_results or not filter_specs:
        return search_results

    # Normalize logic
    logic = filter_logic.upper().strip()
    if logic not in {"AND", "OR"}:
        raise ValueError(f"Unsupported filter_logic '{filter_logic}'. Use 'AND' or 'OR'.")

    # Convert SearchResult objects to dictionaries for the filter engine
    result_dicts: List[Dict[str, Any]] = []
    for result in search_results:
        result_dicts.append(
            {
                "id": result.id,
                "score": result.score,
                "text": result.text,
                "metadata": result.metadata,
            }
        )

    # Use MetadataFilterEngine for AND logic directly
    engine = MetadataFilterEngine()

    if logic == "AND":
        filtered_dicts = engine.apply_filters(result_dicts, filter_specs)
    else:  # OR logic
        # For OR logic, evaluate each field filter separately and union the matches
        matched_indices = set()

        for field_name, field_filter_spec in filter_specs.items():
            # Build a filter dict containing only this single field filter
            single_filter = {field_name: field_filter_spec}
            # Apply engine (which uses AND across fields; here it's just one field)
            field_filtered = engine.apply_filters(result_dicts, single_filter)

            # Record indices of matched results
            ids = {res["id"] for res in field_filtered}
            for idx, original in enumerate(result_dicts):
                if original["id"] in ids:
                    matched_indices.add(idx)

        filtered_dicts = [result_dicts[i] for i in sorted(matched_indices)]

    # Convert back to SearchResult objects, preserving structure
    id_to_result = {r.id: r for r in search_results}
    filtered_results: List[SearchResult] = []
    for res_dict in filtered_dicts:
        original = id_to_result.get(res_dict["id"])
        # Fall back to constructing a new SearchResult if not found
        if original is not None:
            filtered_results.append(original)
        else:
            filtered_results.append(
                SearchResult(
                    id=res_dict.get("id"),
                    score=res_dict.get("score"),
                    text=res_dict.get("text"),
                    metadata=res_dict.get("metadata", {}),
                )
            )

    return filtered_results

