    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable[[List[SearchResult]], Any]]] = None,
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by (looked up on the
            SearchResult top-level attribute first, then in its metadata).
        aggregation_funcs: Optional dictionary mapping statistic_name to an
            aggregation function that accepts a list of SearchResult objects
            belonging to a group and returns a single aggregated value.

            Example:
                {
                    "count": lambda group: len(group),
                    "max_score": lambda group: max(r.score for r in group),
                }

            If None, defaults to:
                - "count": number of results in group
                - "avg_score": average of `score`
                - "max_score": maximum `score`
                - "min_score": minimum `score`

    Returns:
        Dictionary mapping group_value (as string) to aggregated statistics.

        Example:
            {
                "tech": {
                    "count": 5,
                    "avg_score": 0.85,
                    "max_score": 0.95,
                    "min_score": 0.70,
                },
                "unknown": {
                    "count": 2,
                    "avg_score": 0.40,
                    "max_score": 0.50,
                    "min_score": 0.30,
                },
            }
    """
    # Group results by the specified field.
    # The pattern follows MetadataFilterEngine: check top-level first, then metadata.
    groups: Dict[str, List[SearchResult]] = defaultdict(list)

    for result in search_results:
        # Try top-level attribute first
        group_value = getattr(result, group_by_field, None)

        # Fall back to metadata if not found or is None
        if group_value is None:
            metadata = getattr(result, "metadata", {}) or {}
            group_value = metadata.get(group_by_field)

