            scores = [r.score for r in group if getattr(r, "score", None) is not None]
            return max(scores) if scores else 0.0

        def _default_min_score(group: List[SearchResult]) -> float:
            scores = [r.score for r in group if getattr(r, "score", None) is not None]
            return min(scores) if scores else 0.0

        aggregation_funcs = {
            "count": _default_count,
            "avg_score": _default_avg_score,
            "max_score": _default_max_score,
            "min_score": _default_min_score,
        }

    # Compute statistics per group
    aggregated: Dict[str, Dict[str, Any]] = {}

    for group_value, group_results in groups.items():
        stats: Dict[str, Any] = {}
        for stat_name, func in aggregation_funcs.items():
            # Each function receives the list of SearchResult objects in this group
            stats[stat_name] = func(group_results)
        aggregated[group_value] = stats

    return aggregated
