from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict


def _load_meta(index_path: str) -> Dict[str, Any]:
    """
    Helper to load the LEANN meta.json associated with an index_path.

    This replicates the logic in searcher_base._load_meta: meta file lives
    alongside the index file and is named "<index_path.name>.meta.json".
    """
    index_path_obj = Path(index_path)
    meta_path = index_path_obj.parent / f"{index_path_obj.name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Leann metadata file not found at {meta_path}")
    with meta_path.open(encoding="utf-8") as f:
        return json.load(f)


def _iter_passages(index_path: str):
    """
    Helper generator that yields all passages for a given index_path
    using PassageManager.
    """
    meta = _load_meta(index_path)

    # PassageManager expects the meta.json path
    meta_path = (
        Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    ).as_posix()

    pm = PassageManager(passages_source_file=meta_path, meta=meta)
    # PassageManager exposes its passages file(s) via an internal iterator.
    # The JSONL files contain one JSON object per line with keys "text" and "metadata".
    for passage in pm.iter_passages():
        # Normalise to a dict with at least a metadata dict
        if isinstance(passage, dict):
            metadata = passage.get("metadata") or {}
            yield passage, metadata
        else:
            # Fallback if the implementation ever changes; treat as having no metadata
            yield {"text": str(passage), "metadata": {}}, {}


def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Ensure metadata exists (raises FileNotFoundError if not)
    _load_meta(index_path)

    total_passages = 0
    all_fields = set()
    field_value_counts: Dict[str, Counter] = defaultdict(Counter)

    for _, metadata in _iter_passages(index_path):
        total_passages += 1
        for key, value in metadata.items():
            all_fields.add(key)
            # Convert unhashable / complex types to a JSON string for counting
            try:
                field_value_counts[key][value] += 1
            except TypeError:
                serialized = json.dumps(value, sort_keys=True)
                field_value_counts[key][serialized] += 1

    # Convert Counters to plain dicts for JSON-serializability
    field_value_counts_dict: Dict[str, Dict[Any, int]] = {
        field: dict(counter) for field, counter in field_value_counts.items()
    }

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(all_fields),
        "field_value_counts": field_value_counts_dict,
    }


def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Ensure metadata exists (raises FileNotFoundError if not)
    _load_meta(index_path)

    required_fields = list(required_fields)
    if not required_fields:
        # If no required fields, coverage is trivially 100% for all passages
        return {
            "coverage_percentage": 100.0,
            "field_coverage": {},
            "missing_fields": [],
        }

    total_passages = 0
    field_present_counts: Dict[str, int] = {f: 0 for f in required_fields}
    passages_with_all_required = 0

    for _, metadata in _iter_passages(index_path):
        total_passages += 1
        has_all = True
        for field in required_fields:
            if field in metadata and metadata[field] is not None:
                field_present_counts[field] += 1
            else:
                has_all = False
        if has_all:
            passages_with_all_required += 1

    if total_passages == 0:
        coverage_percentage = 0.0
        field_coverage = {f: 0.0 for f in required_fields}
        missing_fields = required_fields[:]  # none present in any passage
    else:
        coverage_percentage = passages_with_all_required / total_passages * 100.0
        field_coverage = {
            field: (count / total_passages * 100.0)
            for field, count in field_present_counts.items()
        }
        missing_fields = [
            field for field, count in field_present_counts.items() if count == 0
        ]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields,
    }
